// src/components/ZoneMap.js
import React, { useState, useEffect } from "react";
import { DISASTER_ZONES, RESOURCES } from "../data/mockData";
import "./ZoneMap.css";

const SEV_COLOR = { critical: "#EF4444", high: "#F59E0B", medium: "#3B82F6", low: "#10B981" };
const SEV_RADIUS = { critical: 28, high: 22, medium: 17, low: 13 };

const TYPE_ICON = {
  medical: "✚",
  rescue:  "⬡",
  food:    "◆",
  shelter: "▲",
};

export default function ZoneMap({ tick }) {
  const [selected, setSelected] = useState(null);
  const [pulseKey, setPulseKey] = useState(0);

  useEffect(() => {
    setPulseKey((k) => k + 1);
  }, [tick]);

  const deployedResources = RESOURCES.filter((r) => r.status === "deployed" && r.assignedZone);

  return (
    <div className="page">
      <div className="page-header">
        <h1>Disaster Zone Map</h1>
        <p>Real-time geographic view of all active disaster zones and deployed resources</p>
      </div>

      <div className="map-layout">
        {/* Map canvas */}
        <div className="card map-card">
          <div className="map-header">
            <div className="card-title" style={{ marginBottom: 0 }}>Live Situation Map</div>
            <div className="map-meta">
              <span className="live-dot" /> <span style={{ fontSize: 11, color: "var(--green)" }}>Live Feed</span>
            </div>
          </div>

          <div className="map-canvas">
            {/* Grid lines */}
            <svg className="map-grid" viewBox="0 0 100 100" preserveAspectRatio="none">
              {[10,20,30,40,50,60,70,80,90].map((v) => (
                <g key={v}>
                  <line x1={v} y1="0" x2={v} y2="100" stroke="#1E2D45" strokeWidth="0.3" />
                  <line x1="0" y1={v} x2="100" y2={v} stroke="#1E2D45" strokeWidth="0.3" />
                </g>
              ))}
            </svg>

            {/* Topographic-style decoration */}
            <svg className="map-topo" viewBox="0 0 800 500" preserveAspectRatio="xMidYMid slice">
              <ellipse cx="350" cy="200" rx="220" ry="130" fill="none" stroke="#1A2D45" strokeWidth="1" opacity="0.6"/>
              <ellipse cx="350" cy="200" rx="170" ry="90" fill="none" stroke="#1A2D45" strokeWidth="0.8" opacity="0.5"/>
              <ellipse cx="350" cy="200" rx="120" ry="55" fill="none" stroke="#1A2D45" strokeWidth="0.6" opacity="0.4"/>
              <ellipse cx="160" cy="380" rx="130" ry="75" fill="none" stroke="#1A2D45" strokeWidth="0.8" opacity="0.4"/>
              <ellipse cx="600" cy="150" rx="150" ry="80" fill="none" stroke="#1A2D45" strokeWidth="0.8" opacity="0.4"/>
              {/* River-like lines */}
              <path d="M0 250 Q200 220 400 260 Q600 300 800 280" fill="none" stroke="#1E3A5A" strokeWidth="2" opacity="0.4"/>
              <path d="M0 270 Q200 240 400 280 Q600 320 800 300" fill="none" stroke="#1E3A5A" strokeWidth="1" opacity="0.25"/>
            </svg>

            {/* Zone markers */}
            {DISASTER_ZONES.map((zone) => {
              const r = SEV_RADIUS[zone.severity];
              const color = SEV_COLOR[zone.severity];
              const cx = `${zone.coordinates.x}%`;
              const cy = `${zone.coordinates.y}%`;
              const isSelected = selected?.id === zone.id;

              return (
                <div
                  key={zone.id}
                  className="zone-marker-wrapper"
                  style={{ left: cx, top: cy }}
                  onClick={() => setSelected(zone)}
                >
                  {/* Outer pulse ring */}
                  <div
                    className="zone-pulse-ring"
                    style={{
                      width: r * 3.2, height: r * 3.2,
                      borderColor: color,
                      animationDelay: zone.severity === "critical" ? "0s" : "0.4s",
                    }}
                  />
                  {/* Inner solid circle */}
                  <div
                    className={`zone-circle ${isSelected ? "zone-selected" : ""}`}
                    style={{
                      width: r * 1.8, height: r * 1.8,
                      background: `${color}22`,
                      border: `2px solid ${color}`,
                      boxShadow: isSelected ? `0 0 20px ${color}55` : `0 0 8px ${color}33`,
                    }}
                  >
                    <span className="zone-type-char">{zone.type[0]}</span>
                  </div>
                  {/* Label */}
                  <div className="zone-label" style={{ color }}>
                    {zone.name.split("—")[0].trim()}
                  </div>
                </div>
              );
            })}

            {/* Resource icons */}
            {deployedResources.map((res) => {
              const zone = DISASTER_ZONES.find((z) => z.id === res.assignedZone);
              if (!zone) return null;
              const offset = { medical: [-20, -10], rescue: [15, -12], food: [-15, 15], shelter: [18, 12] };
              const [ox, oy] = offset[res.type] || [0, 0];
              return (
                <div
                  key={res.id}
                  className="resource-marker"
                  style={{
                    left: `calc(${zone.coordinates.x}% + ${ox}px)`,
                    top: `calc(${zone.coordinates.y}% + ${oy}px)`,
                  }}
                  title={res.name}
                >
                  {TYPE_ICON[res.type]}
                </div>
              );
            })}
          </div>

          {/* Legend */}
          <div className="map-legend">
            <div className="legend-section">
              <div className="legend-title">Severity</div>
              {Object.entries(SEV_COLOR).map(([k, v]) => (
                <div key={k} className="legend-row">
                  <div className="legend-circle" style={{ background: v }} />
                  <span style={{ textTransform: "capitalize" }}>{k}</span>
                </div>
              ))}
            </div>
            <div className="legend-section">
              <div className="legend-title">Resources</div>
              {Object.entries(TYPE_ICON).map(([k, v]) => (
                <div key={k} className="legend-row">
                  <span className="legend-icon">{v}</span>
                  <span style={{ textTransform: "capitalize" }}>{k}</span>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Side panel */}
        <div className="map-side">
          {selected ? (
            <div className="card">
              <div className="card-title">Zone Detail</div>
              <div className="mz-name">{selected.name}</div>
              <div style={{ display: "flex", gap: 8, margin: "10px 0" }}>
                <span className={`badge badge-${selected.severity}`}>{selected.severity}</span>
                <span className="badge badge-medium">{selected.type}</span>
              </div>

              <div className="mz-stats">
                <div className="mz-stat">
                  <div className="mz-stat-label">Affected</div>
                  <div className="mz-stat-val" style={{ color: "#EF4444" }}>{selected.affectedCount.toLocaleString()}</div>
                </div>
                <div className="mz-stat">
                  <div className="mz-stat-label">Population</div>
                  <div className="mz-stat-val">{selected.population.toLocaleString()}</div>
                </div>
                <div className="mz-stat">
                  <div className="mz-stat-label">Resources</div>
                  <div className="mz-stat-val" style={{ color: "#3B82F6" }}>{selected.resourcesDeployed}</div>
                </div>
              </div>

              <div style={{ marginTop: 16 }}>
                <div className="card-title" style={{ marginBottom: 10 }}>Needs Assessment</div>
                {Object.entries(selected.needs).map(([k, v]) => (
                  <div key={k} className="need-row">
                    <span className="need-label" style={{ textTransform: "capitalize" }}>{k}</span>
                    <div className="need-track">
                      <div className="need-fill" style={{
                        width: `${v}%`,
                        background: v >= 75 ? "#EF4444" : v >= 50 ? "#F59E0B" : "#3B82F6"
                      }} />
                    </div>
                    <span className="need-pct">{v}%</span>
                  </div>
                ))}
              </div>

              <div style={{ marginTop: 16 }}>
                <div className="card-title" style={{ marginBottom: 10 }}>Deployed Resources</div>
                {RESOURCES.filter((r) => r.assignedZone === selected.id).map((r) => (
                  <div key={r.id} className="mz-resource">
                    <span className="mz-res-icon">{TYPE_ICON[r.type]}</span>
                    <div>
                      <div style={{ fontSize: 12, fontWeight: 500 }}>{r.name}</div>
                      <div style={{ fontSize: 11, color: "var(--slate)" }}>{r.utilized}/{r.capacity} utilized</div>
                    </div>
                    <span className={`badge badge-${r.status}`}>{r.status}</span>
                  </div>
                ))}
                {RESOURCES.filter((r) => r.assignedZone === selected.id).length === 0 && (
                  <div style={{ fontSize: 12, color: "var(--slate-dim)" }}>No resources assigned</div>
                )}
              </div>
            </div>
          ) : (
            <div className="card">
              <div className="card-title">Zone Summary</div>
              <div style={{ fontSize: 12, color: "var(--slate)", marginBottom: 16 }}>
                Click any zone on the map for details.
              </div>
              <div className="zones-summary">
                {DISASTER_ZONES.map((z) => (
                  <div
                    key={z.id}
                    className="zone-sum-row"
                    onClick={() => setSelected(z)}
                  >
                    <div className="zone-sum-dot" style={{ background: SEV_COLOR[z.severity] }} />
                    <div>
                      <div style={{ fontSize: 12, fontWeight: 500 }}>{z.type}</div>
                      <div style={{ fontSize: 10, color: "var(--slate-dim)" }}>{z.affectedCount.toLocaleString()} affected</div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
